async function loadData(){
  const [products, config] = await Promise.all([fetch(`${basePath}/data/products.json`).then(r=>r.json()), fetch(`${basePath}/data/config.json`).then(r=>r.json())]);
  state.products = products; state.config = config;
}
function logo(){ return `<span class="logo-mark" aria-hidden="true"><svg viewBox="0 0 64 64" fill="none"><rect x="12" y="24" width="40" height="24" rx="6" stroke="currentColor" stroke-width="5"/><path d="M22 16c6-6 14-6 20 0M16 10c10-10 22-10 32 0" stroke="currentColor" stroke-width="5" stroke-linecap="round"/><path d="M29 33l10 6-10 6V33z" fill="currentColor"/></svg></span>`; }
function productImage(p){
  return p.image ? `<img class="product-photo" src="${p.image}" alt="${p.imageAlt || p.name}" loading="lazy">` : `<svg class="product-art" viewBox="0 0 140 140" fill="none"><rect x="24" y="36" width="92" height="58" rx="14" fill="#111827"/><rect x="36" y="48" width="68" height="34" rx="7" fill="#344054"/><circle cx="74" cy="101" r="6" fill="#f97316"/><rect x="52" y="106" width="44" height="8" rx="4" fill="#667085"/><path d="M50 27c12-10 28-10 40 0M40 17c18-16 42-16 60 0" stroke="#16a34a" stroke-width="7" stroke-linecap="round"/></svg>`;
}
function videoEmbed(video){
  if(!video) return '';
  return `<article class="card video-card"><div class="video-frame"><iframe src="https://www.youtube-nocookie.com/embed/${video.id}" title="${video.title}" loading="lazy" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowfullscreen></iframe></div><div class="video-body"><strong>${video.title}</strong><a class="btn btn-outline" href="https://www.youtube.com/watch?v=${video.id}" target="_blank" rel="noopener">${tr('tutorialPlay')}</a></div></article>`;
}
function header(){
  const nav = [[tr('navHome'),`${basePath}/`],[tr('navProducts'),`${basePath}/productos/`],[tr('navCategories'),`${basePath}/#categorias`],[tr('navDeals'),`${basePath}/ofertas/`],[tr('navHow'),`${basePath}/como-comprar/`],[tr('navFaq'),`${basePath}/#faq`],[tr('navAbout'),`${basePath}/sobre-nosotros/`],[tr('navContact'),`${basePath}/contacto/`]];
  document.querySelector('#site-header').innerHTML = `<div class="topbar"><div class="container"><span>${tr('heroEyebrow')} · ${state.config.country}</span><span>${state.config.email} · ${state.config.hours}</span></div></div><header class="header"><div class="container"><nav class="nav"><a class="brand" href="${basePath}/">${logo()}<span class="brand-text"><span>${tr('brandTagline')}</span><strong>VisionBox Tech</strong></span></a><div class="nav-links">${nav.map(([label,url])=>`<a href="${url}">${label}</a>`).join('')}</div><div class="nav-actions"><select class="lang-select" id="lang">${Object.entries(currencies).map(([key,c])=>`<option value="${key}">${c.label}</option>`).join('')}</select><button class="icon-btn" id="cart-open" aria-label="${tr('cart')}">🛒<span class="cart-count" id="cart-count">0</span></button><a class="btn btn-green" href="${waLink(tr('infoMessage'))}">${tr('whatsapp')}</a><button class="icon-btn menu-toggle" id="menu-toggle" aria-label="Menu">☰</button></div></nav><div class="mobile-menu" id="mobile-menu">${nav.map(([label,url])=>`<a href="${url}">${label}</a>`).join('')}</div></div></header>`;
  document.querySelector('#lang').value = state.lang;
  document.querySelector('#lang').addEventListener('change', e => { localStorage.setItem('vbt-lang', e.target.value); location.reload(); });
  document.querySelector('#cart-open').addEventListener('click', openCart);
  document.querySelector('#menu-toggle')?.addEventListener('click',()=>document.querySelector('#mobile-menu').classList.toggle('open'));
}
function footer(){
  document.querySelector('#site-footer').innerHTML = `<footer class="footer"><div class="container footer-grid"><div><a class="brand" href="${basePath}/">${logo()}<span class="brand-text"><span>Portugal</span><strong>VisionBox Tech</strong></span></a><p>${tr('footerText')}</p><div class="payment-icons"><span>${tr('paymentMethod')}</span><span>WhatsApp</span></div></div><div><strong>${tr('navProducts')}</strong><ul><li><a href="${basePath}/productos/">${tr('allProducts')}</a></li><li><a href="${basePath}/ofertas/">${tr('dealsTitle')}</a></li><li><a href="${basePath}/#categorias">${tr('categoriesTitle')}</a></li></ul></div><div><strong>${tr('supportTitle')}</strong><ul><li><a href="${basePath}/soporte/">${tr('guides')}</a></li><li><a href="${basePath}/como-comprar/">${tr('navHow')}</a></li><li><a href="${basePath}/sobre-nosotros/">${tr('navAbout')}</a></li><li><a href="${basePath}/contacto/">${tr('navContact')}</a></li></ul></div><div><strong>${tr('legal')}</strong><ul><li><a href="${basePath}/legal/">${tr('legalTitle')}</a></li><li><a href="${basePath}/legal/#privacidad">${tr('privacy')}</a></li><li><a href="${basePath}/legal/#envios">${tr('deliveries')}</a></li><li><a href="${basePath}/legal/#garantia">${tr('warrantyNav')}</a></li><li><a href="${basePath}/legal/#afiliados">Afiliados</a></li></ul></div><div><strong>${tr('navContact')}</strong><ul><li>${state.config.address}</li><li>${state.config.email}</li><li>${state.config.whatsapp}</li><li>${state.config.hours}</li></ul></div></div><div class="container" style="border-top:1px solid rgba(255,255,255,.12);margin-top:34px;padding-top:20px"><p>© <span id="year"></span> VisionBox Tech. ${tr('independent')}</p></div></footer>`;
  document.querySelector('#year').textContent = new Date().getFullYear();
}
function waLink(message){ const raw = state.config.whatsapp || ''; return raw.includes('[') ? '#' : `https://wa.me/${raw.replace(/\D/g,'')}?text=${encodeURIComponent(message)}`; }
function card(p){ return `<article class="card product-card"><div class="product-media"><span class="badge ${p.oldPrice?'offer':''}">${pc(p,'badge')}</span>${productImage(p)}</div><div class="product-body"><div class="muted">${pc(p,'category')}</div><div class="product-title">${p.name}</div><p class="muted">${pc(p,'summary')}</p><div class="price">${money(p.price)} ${p.oldPrice?`<span class="old-price">${money(p.oldPrice)}</span>`:''}</div><div class="stock ${p.available?'':'out'}">${p.available?pc(p,'stock'):tr('notAvailable')}</div><div class="product-actions"><a class="btn btn-outline" href="${basePath}/productos/${p.slug}/">${tr('details')}</a><button class="btn btn-primary" data-add="${p.slug}" ${p.available?'':'disabled'}>${tr('addCart')}</button></div></div></article>`; }
function wireAddButtons(){ document.querySelectorAll('[data-add]').forEach(btn=>btn.addEventListener('click',()=>addCart(btn.dataset.add))); }
function addCart(slug){ const item = state.cart.find(i=>i.slug===slug); item ? item.qty++ : state.cart.push({slug, qty:1}); saveCart(); openCart(); }
function saveCart(){ localStorage.setItem('vbt-cart', JSON.stringify(state.cart)); updateCartCount(); }
function updateCartCount(){ const el=document.querySelector('#cart-count'); if(el) el.textContent = state.cart.reduce((n,i)=>n+i.qty,0); }
function openCart(){ document.querySelector('#cart-drawer').classList.add('open'); renderCart(); }
function closeCart(){ document.querySelector('#cart-drawer').classList.remove('open'); }
function renderCart(){
  const lines = state.cart.map(i=>({ ...i, product: state.products.find(p=>p.slug===i.slug)})).filter(i=>i.product);
  const subtotal = lines.reduce((sum,i)=>sum+i.product.price*i.qty,0); const shipping = subtotal ? 4.99 : 0; const total=subtotal+shipping;
  document.querySelector('#cart-content').innerHTML = lines.length ? lines.map(i=>`<div class="cart-line"><div><strong>${i.product.name}</strong><div>${money(i.product.price)} · ${pc(i.product,'category')}</div><div class="qty"><button data-qty="${i.slug}" data-delta="-1">−</button><span>${i.qty}</span><button data-qty="${i.slug}" data-delta="1">+</button><button data-remove="${i.slug}">${tr('delete')}</button></div></div><strong>${money(i.product.price*i.qty)}</strong></div>`).join('') : `<p class="muted">${tr('emptyCart')}</p>`;
  document.querySelector('#cart-totals').innerHTML = `<div class="total-line"><span>${tr('subtotal')}</span><strong>${money(subtotal)}</strong></div><div class="total-line"><span>${tr('shipping')}</span><strong>${money(shipping)}</strong></div><div class="total-line"><span>${tr('total')}</span><strong>${money(total)}</strong></div>`;
  document.querySelectorAll('[data-qty]').forEach(b=>b.onclick=()=>{ const item=state.cart.find(i=>i.slug===b.dataset.qty); item.qty += Number(b.dataset.delta); if(item.qty<1) state.cart=state.cart.filter(i=>i.slug!==b.dataset.qty); saveCart(); renderCart(); });
  document.querySelectorAll('[data-remove]').forEach(b=>b.onclick=()=>{ state.cart=state.cart.filter(i=>i.slug!==b.dataset.remove); saveCart(); renderCart(); });
  document.querySelector('#cart-whatsapp').href = waLink(`${tr('orderMessage')} ${lines.map(i=>`${i.qty} x ${i.product.name} (${money(i.product.price)})`).join(', ')}. ${tr('totalEstimate')} ${money(total)}. ${tr('orderConfirm')}`);
}
function cartDrawer(){ document.querySelector('#cart-drawer').innerHTML = `<div class="drawer-backdrop" id="cart-close"></div><aside class="cart-panel"><div style="display:flex;justify-content:space-between;align-items:center;gap:12px"><h2>${tr('cart')}</h2><button class="icon-btn" id="cart-x">×</button></div><div id="cart-content"></div><div id="cart-totals"></div><div class="grid"><a id="cart-whatsapp" class="btn btn-green" href="#">${tr('sendOrder')}</a><button class="btn btn-outline" id="cart-clear">${tr('clearCart')}</button></div></aside>`; document.querySelector('#cart-close').onclick=closeCart; document.querySelector('#cart-x').onclick=closeCart; document.querySelector('#cart-clear').onclick=()=>{state.cart=[];saveCart();renderCart();}; }
function renderHome(){
  const featured = state.products.slice(0,6); const cats=[...new Set(state.products.map(p=>pc(p,'category')))];
  document.querySelector('main').innerHTML = `<section class="hero"><div class="container hero-grid"><div><span class="eyebrow">${tr('heroEyebrow')}</span><h1>${tr('heroTitle')}</h1><p class="lead">${tr('heroText')}</p><p class="muted">${tr('currencyNote')}</p><div class="hero-actions"><a class="btn btn-primary" href="${basePath}/productos/">${tr('seeProducts')}</a><a class="btn btn-dark" href="${waLink(tr('buyWhatsApp'))}">${tr('buyWhatsApp')}</a></div></div><div class="hero-card" aria-label="Streaming devices display"><div class="tv-visual"></div><div class="media-console"></div><div class="device-row"><div class="device"><div class="device-icon">▰</div><strong>TV Box</strong><p class="muted">4K ready</p></div><div class="device"><div class="device-icon">▮</div><strong>Stick</strong><p class="muted">HDMI</p></div><div class="device"><div class="device-icon">⌁</div><strong>Remote</strong><p class="muted">Wireless</p></div></div></div></div></section><section class="section"><div class="container"><div class="section-head"><div><h2>${tr('benefitsTitle')}</h2><p class="muted">${tr('benefitsText')}</p></div></div><div class="grid grid-4">${tr('benefits').map(x=>`<article class="card benefit"><h3>${x}</h3><p class="muted">${tr('benefitText')}</p></article>`).join('')}</div></div></section><section class="section alt" id="productos"><div class="container"><div class="section-head"><div><h2>${tr('featuredTitle')}</h2><p class="muted">${tr('demoText')}</p></div><a class="btn btn-outline" href="${basePath}/productos/">${tr('allProducts')}</a></div><div class="grid grid-3">${featured.map(card).join('')}</div></div></section><section class="section" id="categorias"><div class="container"><h2>${tr('categoriesTitle')}</h2><div class="grid grid-4" style="margin-top:24px">${cats.concat([tr('accessories'),tr('deals')]).map(c=>`<a class="card category-card" href="${basePath}/productos/?cat=${encodeURIComponent(c)}"><strong>${c}</strong><span class="category-icon">→</span></a>`).join('')}</div></div></section>${howBlock()}${compareBlock()}${tutorialsBlock()}${reviewsFaqBlock()}</main>`; wireAddButtons(); }
function howBlock(){ return `<section class="section alt"><div class="container"><h2>${tr('howTitle')}</h2><div class="grid grid-4 steps" style="margin-top:24px">${tr('howSteps').map(x=>`<article class="card step"><h3>${x}</h3><p class="muted">${tr('howStepText')}</p></article>`).join('')}</div></div></section>`; }
function tutorialsBlock(){ return `<section class="section"><div class="container"><div class="section-head"><div><h2>${tr('tutorialsTitle')}</h2><p class="muted">${tr('tutorialsText')}</p></div><a class="btn btn-outline" href="${basePath}/soporte/">${tr('supportTitle')}</a></div><div class="grid grid-3">${state.products.slice(0,6).map(p=>videoEmbed(p.tutorial)).join('')}</div></div></section>`; }
function compareBlock(){ const rows=['resolution','os','price','recommendedUse']; const labels=tr('compareLabels'); return `<section class="section"><div class="container"><h2>${tr('compareTitle')}</h2><div class="compare-wrap" style="margin-top:24px"><table><thead><tr><th>${labels.data}</th>${state.products.slice(0,4).map(p=>`<th>${p.name}</th>`).join('')}</tr></thead><tbody>${rows.map(r=>`<tr><th>${labels[r]}</th>${state.products.slice(0,4).map(p=>`<td>${r==='price'?money(p.price):r==='recommendedUse'?pc(p,'recommendedUse'):p[r]}</td>`).join('')}</tr>`).join('')}</tbody></table></div></div></section>`; }
function reviewsFaqBlock(){ return `<section class="section alt" id="faq"><div class="container"><div class="notice"><h2>${tr('reviewsTitle')}</h2><p>${tr('reviewsText')}</p></div><h2 style="margin-top:42px">${tr('faqTitle')}</h2><div class="faq" style="margin-top:22px">${faqData[state.lang].map(([q,a])=>`<details><summary>${q}</summary><p class="muted">${a}</p></details>`).join('')}</div></div></section>`; }
function renderProducts(){ document.querySelector('main').innerHTML = `<section class="section"><div class="container"><h1>${tr('allProducts')}</h1><p class="muted">${tr('currencyNote')}</p><div class="controls"><input class="input" id="q" placeholder="${tr('search')}"><select class="filter-select" id="cat"><option value="">${tr('category')}</option>${[...new Set(state.products.map(p=>pc(p,'category')))].map(c=>`<option>${c}</option>`).join('')}</select><select class="filter-select" id="price"><option value="">${tr('price')}</option><option value="0-30">0-30</option><option value="30-60">30-60</option><option value="60-999">60+</option></select><select class="filter-select" id="avail"><option value="">${tr('availability')}</option><option value="true">${tr('available')}</option><option value="false">${tr('outOfStock')}</option></select><select class="sort-select" id="sort"><option value="popular">${tr('popular')}</option><option value="low">${tr('lowPrice')}</option><option value="high">${tr('highPrice')}</option></select></div><div class="grid grid-3" id="catalog"></div></div></section>`; const render=()=>{ let list=[...state.products]; const q=document.querySelector('#q').value.toLowerCase(); const cat=document.querySelector('#cat').value; const pr=document.querySelector('#price').value; const av=document.querySelector('#avail').value; const sort=document.querySelector('#sort').value; if(q) list=list.filter(p=>p.name.toLowerCase().includes(q)); if(cat) list=list.filter(p=>pc(p,'category')===cat); if(pr){const [a,b]=pr.split('-').map(Number); list=list.filter(p=>p.price>=a&&p.price<=b);} if(av) list=list.filter(p=>String(p.available)===av); list.sort((a,b)=>sort==='low'?a.price-b.price:sort==='high'?b.price-a.price:b.popular-a.popular); document.querySelector('#catalog').innerHTML=list.map(card).join(''); wireAddButtons();}; document.querySelectorAll('.controls input,.controls select').forEach(el=>el.addEventListener('input',render)); render(); }
function renderDeals(){ const deals=state.products.filter(p=>p.oldPrice); document.querySelector('main').innerHTML=`<section class="section"><div class="container"><h1>${tr('dealsTitle')}</h1><p class="lead">${tr('dealsLead')}</p><div class="grid grid-3" style="margin-top:26px">${deals.map(card).join('')}</div></div></section>`; wireAddButtons(); }
function renderProductDetail(){ const slug=location.pathname.split('/').filter(Boolean).pop(); const p=state.products.find(x=>x.slug===slug) || state.products[0]; const labels=tr('compareLabels'); document.title=`${p.name} | VisionBox Tech`; document.querySelector('main').innerHTML=`<section class="section"><div class="container"><div class="breadcrumb"><a href="${basePath}/productos/">${tr('breadcrumbProducts')}</a> / ${p.name}</div><div class="product-detail"><div><div class="gallery">${productImage(p)}</div>${p.imageCredit?`<p class="image-credit">${tr('source')}: <a href="${p.imageCredit.url}" target="_blank" rel="noopener">${p.imageCredit.label}</a></p>`:''}</div><div><span class="eyebrow">${pc(p,'category')}</span><h1>${p.name}</h1><p class="lead">${pc(p,'description')}</p><div class="price">${money(p.price)} ${p.oldPrice?`<span class="old-price">${money(p.oldPrice)}</span>`:''}</div><p class="muted">${tr('currencyNote')}</p><p class="stock ${p.available?'':'out'}">${p.available?pc(p,'stock'):tr('notAvailable')}</p><div class="hero-actions"><button class="btn btn-primary" data-add="${p.slug}" ${p.available?'':'disabled'}>${tr('addCart')}</button><a class="btn btn-green" href="${waLink(`${tr('interested')} ${p.name}, ${tr('price').toLowerCase()} ${money(p.price)}. ${tr('confirmProduct')}`)}">${tr('buyWhatsApp')}</a></div><div class="detail-list">${[[labels.resolution,p.resolution],[labels.os,p.os],[labels.price,money(p.price)],[labels.recommendedUse,pc(p,'recommendedUse')]].map(([k,v])=>`<div><strong>${k}</strong><br><span class="muted">${v}</span></div>`).join('')}</div><h2>${tr('featuresTitle')}</h2><ul>${pc(p,'features').map(x=>`<li>${x}</li>`).join('')}</ul><h2>${tr('boxTitle')}</h2><ul>${pc(p,'box').map(x=>`<li>${x}</li>`).join('')}</ul><h2>${tr('compatibilityTitle')}</h2><p>${pc(p,'compatibility').join(', ')}. ${pc(p,'warranty')} ${pc(p,'shipping')}</p></div></div></div></section><section class="section alt"><div class="container"><h2>${tr('tutorialsTitle')}</h2>${videoEmbed(p.tutorial)}</div></section><section class="section"><div class="container"><h2>${tr('relatedTitle')}</h2><div class="grid grid-3">${state.products.filter(x=>x.slug!==p.slug).slice(0,3).map(card).join('')}</div></div></section>`; wireAddButtons(); }
function renderInfo(page){ const map={how:[tr('howTitle'),`${tr('howLead')} ${tr('paymentMethod')}. WhatsApp.`],support:[tr('supportTitle'),tr('supportLead')],contact:[tr('contactTitle'),tr('contactLead')]}; const [title,txt]=map[page]; document.querySelector('main').innerHTML=`<section class="section"><div class="container"><h1>${title}</h1><p class="lead">${txt}</p>${page==='contact'?contactForm():page==='support'?supportContent():howBlock()}</div></section>`; if(page==='contact') wireForm(); }
function supportContent(){ return `<div class="guide-grid">${guideData[state.lang].map(([title,steps,notes], index)=>`<article class="card article-card"><div class="article-visual" aria-hidden="true">${logo()}</div><div class="article-body"><p class="meta">${guideAuthor} · ${guideMeta[index].date}</p><h2>${title}</h2><p>${steps}</p><p class="muted">${notes}</p><a class="btn btn-outline" href="${basePath}/guias/${guideMeta[index].slug}/">${tr('details')}</a></div></article>`).join('')}</div><section class="section compact"><h2>${tr('tutorialsTitle')}</h2><p class="muted">${tr('tutorialsText')}</p><div class="grid grid-3" style="margin-top:22px">${state.products.map(p=>videoEmbed(p.tutorial)).join('')}</div></section>`; }
function renderGuide(){ const slug=location.pathname.split('/').filter(Boolean).pop(); const index=guideMeta.findIndex(g=>g.slug===slug); const guide=guideData[state.lang][index >= 0 ? index : 0]; const meta=guideMeta[index >= 0 ? index : 0]; document.title=`${guide[0]} | VisionBox Tech`; document.querySelector('main').innerHTML=`<section class="section"><div class="container"><div class="breadcrumb"><a href="${basePath}/soporte/">${tr('supportTitle')}</a> / ${guide[0]}</div><article class="card legal-list" style="padding:28px"><p class="meta">${guideAuthor} · ${meta.date}</p><h1>${guide[0]}</h1><p class="lead">${guide[1]}</p><h2>${tr('supportTitle')}</h2><p class="muted">${guide[2]}</p><div class="article-visual" style="min-height:180px;border-radius:14px;margin-top:22px" aria-hidden="true">${logo()}</div></article></div></section>`; }
function contactForm(){ return `<form class="card form" id="contact-form" style="padding:24px;max-width:760px"><label>${tr('name')}<input class="input" name="name" required minlength="2"></label><label>${tr('email')}<input class="input" name="email" type="email" required></label><label>${tr('message')}<textarea class="input" name="message" required minlength="10"></textarea></label><a class="btn btn-outline" href="mailto:${state.config.email}">${state.config.email}</a><button class="btn btn-primary" type="submit">${tr('sendOrder')}</button><p id="form-status" class="muted"></p></form>`; }
function wireForm(){ document.querySelector('#contact-form').addEventListener('submit',e=>{e.preventDefault(); const data=new FormData(e.currentTarget); const text=`${tr('name')}: ${data.get('name')} | ${tr('email')}: ${data.get('email')} | ${tr('message')}: ${data.get('message')}`; document.querySelector('#form-status').textContent=tr('formOk'); window.open(waLink(text),'_blank','noopener');}); }
function renderLegal(){ document.querySelector('main').innerHTML=`<section class="section"><div class="container"><h1>${tr('legalTitle')}</h1><p class="lead">${tr('legalLead')}</p><div class="legal-list">${legalData[state.lang].map(([id,title,body])=>`<article class="card" id="${id}"><h2>${title}</h2><p class="muted">${body}</p>${id==='afiliados'?'':`<p>${tr('independent')}</p>`}</article>`).join('')}</div></div></section>`; }
function renderAbout(){ const [title, body] = aboutData[state.lang]; document.querySelector('main').innerHTML=`<section class="section"><div class="container"><h1>${title}</h1><p class="lead">${body}</p><div class="grid grid-3" style="margin-top:28px"><article class="card benefit"><h2>${tr('navProducts')}</h2><p class="muted">${tr('footerText')}</p></article><article class="card benefit"><h2>${tr('supportTitle')}</h2><p class="muted">${tr('supportLead')}</p></article><article class="card benefit"><h2>${tr('navContact')}</h2><p class="muted">${state.config.address}<br>${state.config.email}<br>${state.config.whatsapp}</p></article></div></div></section>`; }
function render404(){ document.querySelector('main').innerHTML=`<section class="section"><div class="container"><h1>${tr('notFoundTitle')}</h1><p class="lead">${tr('notFoundText')}</p><a class="btn btn-primary" href="${basePath}/">${tr('backHome')}</a></div></section>`; }
async function init(){ await loadData(); document.documentElement.lang = state.lang === 'us' ? 'en' : state.lang; header(); footer(); cartDrawer(); updateCartCount(); const page=document.body.dataset.page; if(page==='home') renderHome(); if(page==='products') renderProducts(); if(page==='deals') renderDeals(); if(page==='product') renderProductDetail(); if(page==='guide') renderGuide(); if(page==='how') renderInfo('how'); if(page==='support') renderInfo('support'); if(page==='contact') renderInfo('contact'); if(page==='legal') renderLegal(); if(page==='about') renderAbout(); if(page==='404') render404(); }
init();
